/** A mutable counter. */
export let counter = 0

/** An inferred-type constant (no annotation). */
export const inferred = { a: 1, b: 'hello' }

/** A constant with explicit type. */
export const typed: number = 42

/** A boolean flag. */
export const FLAG = true

/** A null value. */
export const EMPTY = null

/** An array. */
export const LIST = [1, 2, 3]

/** An object literal. */
export const CONFIG = { debug: false }

/** A bigint-like expression. */
export const BIG = 99999999999
